patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,10 +1,10 @@
 module mux_4to1 (
   input [7:0] data0, data1, data2, data3,
   input [1:0] sel,
   output reg [7:0] mux_out
 );

-  always @(data0 or data1) begin
+  always @(data0 or data1 or data2 or data3 or sel) begin
     case (sel)
       2'b00: mux_out = data0;
       2'b01: mux_out = data1;
       2'b10: mux_out = data2;

before_code:
module mux_4to1 (
  input [7:0] data0, data1, data2, data3,
  input [1:0] sel,
  output reg [7:0] mux_out
);

  always @(data0 or data1) begin
    case (sel)
      2'b00: mux_out = data0;
      2'b01: mux_out = data1;
      2'b10: mux_out = data2;
      2'b11: mux_out = data3;
    endcase
  end
endmodule

after_code:
module mux_4to1 (
  input [7:0] data0, data1, data2, data3,
  input [1:0] sel,
  output reg [7:0] mux_out
);

  always @(data0 or data1 or data2 or data3 or sel) begin
    case (sel)
      2'b00: mux_out = data0;
      2'b01: mux_out = data1;
      2'b10: mux_out = data2;
      2'b11: mux_out = data3;
    endcase
  end
endmodule
